const messages = [
  'Quelle ville française vous correspond vraiment ? On a classé 540 villes sur 8 critères (vie, transport, nature, coût, sécurité, culture, télétravail, écoles). Sans bullshit, données SSMSI + Insee + observatoires des loyers. 👉 https://mavilleideale.fr',
  'Top 3 villes pour le télétravail en 2026, données à l\'appui : 👉 https://mavilleideale.fr/classements/teletravail',
  'Climat 2040 par région française : ce qui change vraiment chez vous. 👉 https://mavilleideale.fr/guides',
  'Acheter ou louer en 2026 ? On a calculé le seuil par ville. 👉 https://mavilleideale.fr',
  'Vivre sans voiture en France : les 12 villes où c\'est réaliste. 👉 https://mavilleideale.fr/guides'
];
const pick = messages[Math.floor(Math.random() * messages.length)];
return [{ json: { message: pick } }];
